def polynomial_features_1d(x, degree):
    x = np.asarray(x, dtype=float).reshape(-1, 1)
    columns = [np.ones((x.shape[0], 1))]
    columns.extend(x ** power for power in range(1, degree + 1))
    return np.hstack(columns)












